sql:
SELECT dataset_id
FROM datasets
WHERE dataset_id > (SELECT AVG(dataset_id) FROM demographics);

SELECT 
    (SELECT source_name FROM sources WHERE reliability = 'High') AS source_name, 
    (SELECT user_name FROM users WHERE user_id = 0) AS user_name;

external_knowledge:
- "demographics" refers to the data about people and their characteristics;
- "sources" include government censuses and other authoritative data providers;
- "age and gender" are key demographic factors for population analysis;
- "migration patterns" refer to movements of individuals or groups from one location to another;
- "educational attainment" indicates the highest level of education completed;
- "employment status" includes whether individuals are employed, unemployed, or out of the workforce.

sql:
SELECT SUM(total_population) AS total_population_of_epirus
FROM demographics
WHERE location = 'Epirus';

SELECT source_name 
FROM sources 
WHERE source_id IN (
  SELECT source_id 
  FROM datasets
);

SELECT updated_at
FROM demographics
WHERE updated_at = (
  SELECT MAX(updated_at)
  FROM demographics
);

SELECT user_name
FROM users
WHERE last_login = (
    SELECT MAX(last_login) 
    FROM users
);
